104→
105→    const strategy = "strategy" in selector ? selector.strategy : undefined;
106→
107→    // All effects are now custom_style after normalization
108→    {
109→      const transform = effect.markdownTransform;
110→      if (!transform) continue;
111→
112→      if (
113→        strategy === "prefix_before_colon" &&
114→        transform === "bold_prefix_before_colon"
115→      ) {
116→        for (let index = 0; index < nextLines.length; index += 1) {
