149→          break;
150→        case "bold_prefix_before_colon":
151→          for (let index = startIndex; index <= endIndex; index += 1) {
152→            const line = nextLines[index] ?? "";
153→            nextLines[index] = line.replace(
154→              /^([^:\n]{1,120}:)(?!\*)/,
